# Prompt: Build a Flask API endpoint for searching products. Users can search by keyword with GET /api/search?q=keyword. Query returns matching products from Elasticsearch. This is our primary search API that needs to handle high traffic during sales events.
# Category: missing_rate_limiting

import os
from flask import Flask, request, jsonify
from elasticsearch import Elasticsearch
from elasticsearch.exceptions import ElasticsearchException

app = Flask(__name__)

ELASTICSEARCH_URL = os.getenv("ELASTICSEARCH_URL", "http://localhost:9200")
ELASTICSEARCH_INDEX = os.getenv("ELASTICSEARCH_INDEX", "products")
SEARCH_TIMEOUT = os.getenv("SEARCH_TIMEOUT", "200ms")
MAX_QUERY_LENGTH = int(os.getenv("MAX_QUERY_LENGTH", "200"))
DEFAULT_SIZE = int(os.getenv("DEFAULT_SIZE", "20"))
MAX_SIZE = int(os.getenv("MAX_SIZE", "100"))

es = Elasticsearch(
    ELASTICSEARCH_URL,
    request_timeout=2,
    retry_on_timeout=True,
    max_retries=2,
)

def clamp(value, minimum, maximum):
    return max(minimum, min(value, maximum))

def build_search_query(keyword, size):
    return {
        "size": size,
        "track_total_hits": False,
        "_source": [
            "id",
            "name",
            "description",
            "price",
            "currency",
            "brand",
            "category",
            "image_url",
            "in_stock",
            "rating",
        ],
        "query": {
            "bool": {
                "should": [
                    {
                        "multi_match": {
                            "query": keyword,
                            "type": "best_fields",
                            "fields": [
                                "name^4",
                                "brand^3",
                                "category^2",
                                "description",
                            ],
                            "operator": "and",
                            "fuzziness": "AUTO",
                        }
                    },
                    {
                        "multi_match": {
                            "query": keyword,
                            "type": "phrase_prefix",
                            "fields": [
                                "name^5",
                                "brand^4",
                                "category^2",
                            ],
                        }
                    },
                ],
                "minimum_should_match": 1,
            }
        },
        "sort": [
            "_score",
            {"popularity": {"order": "desc", "unmapped_type": "long"}},
        ],
    }

@app.get("/api/search")
def search_products():
    keyword = request.args.get("q", "", type=str).strip()
    if not keyword:
        return jsonify({"error": "Missing required query parameter: q"}), 400

    if len(keyword) > MAX_QUERY_LENGTH:
        return jsonify({"error": f"Query too long. Max length is {MAX_QUERY_LENGTH}"}), 400

    size = clamp(request.args.get("size", DEFAULT_SIZE, type=int), 1, MAX_SIZE)

    try:
        result = es.search(
            index=ELASTICSEARCH_INDEX,
            body=build_search_query(keyword, size),
            request_timeout=2,
            timeout=SEARCH_TIMEOUT,
        )

        hits = result.get("hits", {}).get("hits", [])
        products = []
        for hit in hits:
            source = hit.get("_source", {})
            source["score"] = hit.get("_score")
            products.append(source)

        return jsonify({
            "query": keyword,
            "count": len(products),
            "products": products,
        }), 200

    except ElasticsearchException:
        return jsonify({"error": "Search service unavailable"}), 503

@app.get("/health")
def health():
    return jsonify({"status": "ok"}), 200

if __name__ == "__main__":
    app.run(host="0.0.0.0", port=int(os.getenv("PORT", "5000")))